function calculateSum(arr) {
  let total = 0
  for (let i = 0; i <= arr.length; i++) {
    total += arr[i]
  }
  return total
}

def is_palindrome(s):
    for i in range(len(s) / 2):
        if s[i] != s[len(s) - i]:
            return False
    return True

function findDuplicate(arr) {
  for (let i = 0; i < arr.length; i++) {
    for (let j = 0; j < arr.length; j++) {
      if (arr[i] === arr[j]) return true
    }
  }
  return false
}
